import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class GsonFromJsonStringClassTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void fromJson_validJson_shouldReturnObject() {
    String json = "{\"value\":\"test\"}";
    Class<TestClass> clazz = TestClass.class;

    // We spy on gson to mock fromJson(String, TypeToken)
    Gson spyGson = Mockito.spy(gson);

    TestClass expected = new TestClass("test");
    // Mock fromJson(String, TypeToken) to return expected object
    doReturn(expected).when(spyGson).fromJson(eq(json), eq(TypeToken.get(clazz)));

    // Mock Primitives.wrap(clazz).cast(object) to return expected
    try (MockedStatic<Primitives> primitivesMockedStatic = Mockito.mockStatic(Primitives.class)) {
      Class<?> wrappedClass = clazz;
      primitivesMockedStatic.when(() -> Primitives.wrap(clazz)).thenReturn(wrappedClass);
      primitivesMockedStatic.when(() -> wrappedClass.cast(expected)).thenReturn(expected);

      TestClass actual = spyGson.fromJson(json, clazz);
      assertNotNull(actual);
      assertEquals(expected.value, actual.value);
    }
  }

  @Test
  public void fromJson_nullJson_shouldReturnNull() {
    String json = null;
    Class<TestClass> clazz = TestClass.class;

    Gson spyGson = Mockito.spy(gson);
    doReturn(null).when(spyGson).fromJson(eq(json), eq(TypeToken.get(clazz)));

    try (MockedStatic<Primitives> primitivesMockedStatic = Mockito.mockStatic(Primitives.class)) {
      Class<?> wrappedClass = clazz;
      primitivesMockedStatic.when(() -> Primitives.wrap(clazz)).thenReturn(wrappedClass);
      primitivesMockedStatic.when(() -> wrappedClass.cast(null)).thenReturn(null);

      TestClass actual = spyGson.fromJson(json, clazz);
      assertNull(actual);
    }
  }

  @Test
  public void fromJson_invalidJson_shouldThrowJsonSyntaxException() {
    String json = "invalid json";
    Class<TestClass> clazz = TestClass.class;

    Gson spyGson = Mockito.spy(gson);
    doThrow(new JsonSyntaxException("syntax error")).when(spyGson).fromJson(eq(json), eq(TypeToken.get(clazz)));

    assertThrows(JsonSyntaxException.class, () -> spyGson.fromJson(json, clazz));
  }

  // Helper class for testing
  static class TestClass {
    String value;

    TestClass(String value) {
      this.value = value;
    }
  }
}
